INSERT INTO `jarvis_pending_actions` VALUES (119,'1487662980056219768','1324852262186516565','INSERT INTO reminders (title, remind_at, recurrence_type) VALUES (\'Save all code to G-Drive\', \'2026-03-29 00:01:34\', \'none\')','2026-03-29 04:01:36'),(120,'1487663112881700975','1324852262186516565','INSERT INTO todos (list_id, title) VALUES (16, \'Check out the top 50 skill.md files for Claude\')','2026-03-29 04:02:10'),(121,'1487663112881700975','1324852262186516565','DELETE FROM reminders WHERE content LIKE \'%Check out the top 50 skill.md files for Claude%\'','2026-03-29 04:02:16'),(122,'1487663112881700975','1324852262186516565','DELETE FROM reminders WHERE title LIKE \'%Check out the top 50 skill.md files for Claude%\'','2026-03-29 04:02:21'),(123,'1487663112881700975','1324852262186516565','DELETE FROM reminders WHERE id = 27','2026-03-29 04:02:28'),(125,'1487919819650105534','1324852262186516565','INSERT INTO todos (list_id, title) VALUES (7, \'Text Abe Gulko about getting him 2 permanent timeslots weekly\')','2026-03-29 21:02:14'),(127,'1488202867453067535','1324852262186516565','INSERT INTO reminders (title, remind_at) VALUES (\'Eat\', \'2026-03-30 12:16:55\')','2026-03-30 15:46:58'),(129,'1489195758711472168','1324852262186516565','DELETE FROM todos WHERE list_id = 35 AND title LIKE \'%getting rid of%shoe rack%\';','2026-04-02 09:32:23'),(130,'1489195854425362494','1324852262186516565','DELETE FROM todos WHERE list_id = 35 AND title LIKE \'%get rid of shoe rack%\';','2026-04-02 09:32:44'),(139,'1498843599943630920','1324852262186516565','DELETE FROM reminders WHERE title = \'Cancel Sabrina Blum\' AND remind_at = \'2026-04-29 07:30:00\'','2026-04-29 00:29:23'),(140,'1498843599943630920','1324852262186516565','DELETE FROM reminders WHERE title = \'Cancel Sabrina Blum\' AND remind_at = \'2026-04-29 07:00:00\' LIMIT 1','2026-04-29 00:29:28');
